import React from 'react';
import { View, Text, Image } from 'react-native';

function PokedexItem({ data, length }) {
  return (
    <View key={data.id}>
      <Text>{data.name}</Text>
      <Image source={{ uri: data.image }} style={{ width: 100, height: 100 }} />
    </View>
  );
}

export default PokedexItem;
